import{_ as t,o as r,c as a,a5 as o}from"./chunks/framework.B5tqjWbr.js";const p=JSON.parse('{"title":"学习记录 #0026：三电平P/O/N工作状态判别","description":"","frontmatter":{"date":"2026-06-15T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"学习记录 #0026：三电平P/O/N工作状态判别","tags":["power-electronics"],"status":"learning","summary":"**日期**：2026-06-15 **课程**：第30课 — 三电平P/O/N工作状态判别（Phase 2核心概念深化） **状态**：进行中"},"headers":[],"relativePath":"content/power/archive/old-learning-records/0026-three-level-pon-states.md","filePath":"content/power/archive/old-learning-records/0026-three-level-pon-states.md","lastUpdated":null}'),l={name:"content/power/archive/old-learning-records/0026-three-level-pon-states.md"};function i(n,e,s,c,d,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="学习记录-0026-三电平p-o-n工作状态判别" tabindex="-1">学习记录 #0026：三电平P/O/N工作状态判别 <a class="header-anchor" href="#学习记录-0026-三电平p-o-n工作状态判别" aria-label="Permalink to &quot;学习记录 #0026：三电平P/O/N工作状态判别&quot;">​</a></h1><p><strong>日期</strong>：2026-06-15 <strong>课程</strong>：第30课 — 三电平P/O/N工作状态判别（Phase 2核心概念深化） <strong>状态</strong>：进行中</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><ol><li><strong>P/O/N符号</strong>：P=+Vdc/2（正母线），O=0（中点），N=-Vdc/2（负母线）；三个字母依次代表A/B/C三相</li><li><strong>电流方向约束是维也纳的核心限制</strong>：ix&gt;0时只能输出{P,O}，ix&lt;0时只能输出{N,O}——因为二极管续流方向由电流极性决定</li><li><strong>NPC无此约束</strong>：NPC每相有4个全控开关，可主动连接P/O/N任意电平，27种状态全部可用</li><li><strong>每扇区8个可用状态</strong>：三相电流正负组合将αβ平面分为6个60°扇区，每扇区2×2×2=8种可用状态</li><li><strong>中点电流判别规则</strong>：只有O状态的相电流流过中点，iN = Σ(处于O状态的相电流)</li><li><strong>冗余小矢量对中点电流相反</strong>：POO的iN=ib+ic=-ia，ONN的iN=ia，两者对中点充放电作用相反</li><li><strong>三步判别法</strong>：①确定电流方向 → ②确定每相可输出电平集合 → ③检查目标状态每相是否在集合中</li></ol><h2 id="待深入问题" tabindex="-1">待深入问题 <a class="header-anchor" href="#待深入问题" aria-label="Permalink to &quot;待深入问题&quot;">​</a></h2><ul><li>[ ] 电流过零畸变的本质原因和消除方法？</li><li>[ ] 12扇区（30°）与6扇区（60°）划分的工程取舍？</li><li>[ ] 调制度&gt;0.9时可用矢量减少对SVPWM的影响？</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>继续深入三电平SVPWM的工程实现细节</p>',8)])])}const P=t(l,[["render",i]]);export{p as __pageData,P as default};
